import{c as r,Q as e,j as a,m as o}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"제12장 서비스 배포와 엔지니어링","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part3-practice/chapter12.md","filePath":"ko/part3-practice/chapter12.md"}'),p={name:"ko/part3-practice/chapter12.md"};function n(s,t,i,c,l,_){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="제12장-서비스-배포와-엔지니어링" tabindex="-1">제12장 서비스 배포와 엔지니어링 <a class="header-anchor" href="#제12장-서비스-배포와-엔지니어링" aria-label="Permalink to &quot;제12장 서비스 배포와 엔지니어링&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>로컬 머신에서 작동하는 AI 애플리케이션을 구축하는 것은 한 가지이지만, 수천 명의 사용자에게 24시간 안정적으로 작동시키는 것은 완전히 다른 문제입니다.</p><p>이 챕터의 내용:</p><ul><li><strong>서비스 배포 필수 지식</strong>: Docker, Kubernetes, 클라우드 플랫폼</li><li><strong>API 설계 모범 사례</strong>: REST, 인증, 속도 제한</li><li><strong>모니터링과 可观测性</strong>: 로깅, 메트릭스, 알림</li><li><strong>AI 애플리케이션 CI/CD</strong>: 자동화된 테스트와 배포 파이프라인</li><li><strong>비용 최적화</strong>: API 비용 관리, 캐싱 전략</li><li><strong>보안 고려 사항</strong>: API 키, 데이터 프라이버시, 프롬프트 인젝션 방어</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter12.html">中文版阅读</a></p></blockquote>',7)])])}const g=r(p,[["render",n]]);export{d as __pageData,g as default};
